     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
-      if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
+    if (isa<PHINode>(&I) && BB == TheLoop->getHeader()) {
+      PHINode *PN = cast<PHINode>(&I);
+      if (PN->use_empty())
+        return true; /* Dead phi indicates simplification */
+      return false;
+    }
+    bool HasRealUse = false; 
+    for (User *U : PN->users()) { 
+      if (!isa<PHINode>(U) || cast<PHINode>(U)->getParent() != TheLoop->getHeader()) { 
+        HasRealUse = true; 
+        break; 
+      } 
+    } 
+    if (!HasRealUse) 
+      return true; 
+    return false; 
+  }
         return false;
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
